  3326 | // Return true if we can safely remove the select instruction for std::bit_ceil
  3327 | // pattern.
  3328 | static bool isSafeToRemoveBitCeilSelect(ICmpInst::Predicate Pred, Value *Cond0,
  3329 |                                         const APInt *Cond1, Value *CtlzOp,
  3330 |                                         unsigned BitWidth) {
  3331 |   // The challenge in recognizing std::bit_ceil(X) is that the operand is used
  3332 |   // for the CTLZ proper and select condition, each possibly with some
  3333 |   // operation like add and sub.
  3334 |   //
  3335 |   // Our aim is to make sure that -ctlz & (BitWidth - 1) == 0 even when the
  3336 |   // select instruction would select 1, which allows us to get rid of the select
  3337 |   // instruction.
  3338 |   //
  3339 |   // To see if we can do so, we do some symbolic execution with ConstantRange.
  3340 |   // Specifically, we compute the range of values that Cond0 could take when
  3341 |   // Cond == false.  Then we successively transform the range until we obtain
  3342 |   // the range of values that CtlzOp could take.
  3343 |   //
