diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..e536af36da2b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3165,6 +3165,28 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       if (B == D)
         return OrFactorization(B, A, C, CondLogicOr && TrueLogicOr);
     }
+    // select (select other_cond, icmp1, false), icmp2, false
+    // where icmp1 and icmp2 form a range check that can be simplified
+    // --> select other_cond, simplified_icmp, false
+    if (auto *InnerSel = dyn_cast<SelectInst>(CondVal)) {
+      Value *InnerCond = InnerSel->getCondition();
+      Value *InnerTrue = InnerSel->getTrueValue();
+      Value *InnerFalse = InnerSel->getFalseValue();
+      if (match(InnerFalse, m_Zero()) && isa<ICmpInst>(InnerTrue) &&
+          isa<ICmpInst>(TrueVal)) {
+        auto *ICmp0 = cast<ICmpInst>(InnerTrue);
+        auto *ICmp1 = cast<ICmpInst>(TrueVal);
+        // Try to combine the two icmps using simplifyRangeCheck
+        // Pattern: (x s>= 0) && (x s< n) --> x u< n
+        if (Value *V = simplifyRangeCheck(ICmp0, ICmp1, /*Inverted=*/false)) {
+          return SelectInst::Create(InnerCond, V, Zero);
+        }
+        // Try the other order
+        if (Value *V = simplifyRangeCheck(ICmp1, ICmp0, /*Inverted=*/false)) {
+          return SelectInst::Create(InnerCond, V, Zero);
+        }
+      }
+    }
   }

